css:
.loader {color: var(--loader-color, #be123c);
  --loader-secondary-color: #fda4af;
  --loader-bg: #ffffff;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #be123c);
   box-shadow: 30px 0 var(--loader-secondary-color, #fda4af);
   animation: l4-1 1s infinite alternate, l4-2 .5s infinite alternate;
}
@keyframes l4-1  {
  0%,40% {transform: rotate(0)}
80%,100% {transform: rotate(.5turn)}
}
@keyframes l4-2  {
  80%,100% {box-shadow: 16px 0 var(--loader-secondary-color, #fda4af)}
}
